class Solution {
    public String breakPalindrome(String palindrome) {
        int length = palindrome.length();
        for (int i = 0; i < length / 2; i++) {
            char firstChar = palindrome.charAt(i);
            char secondChar = palindrome.charAt(length - i - 1);
            if (isSmaller(firstChar, secondChar)) {
                palindrome = breakPalindromeHelper(palindrome, firstChar, secondChar);
            }
        }
        return palindrome;
    }

    private String breakPalindromeHelper(String palindrome, char firstChar, char secondChar) {
        int length = palindrome.length();
        for (int i = 0; i < length / 2; i++) {
            char firstChar = palindrome.charAt(i);
            char secondChar = palindrome.charAt(length - i - 1);
            if (isSmaller(firstChar, secondChar)) {
                palindrome = breakPalindromeHelper(palindrome, firstChar, secondChar);
            }
        }
        return palindrome;
    }

    private boolean isSmaller(char a, char b) {
        return a < b;
    }
}
